    def is_leap_year(year):
        if year % 400 == 0:
            leap = True
        elif year % 100 == 0:
            leap = False
        elif year % 4 == 0:
            leap = True
        else:
            leap = False

    def days_before_year(year):
        previous_year = year - 1
        total = previous_year * 365
        total = total + (previous_year // 4)
        total = total - (previous_year // 100)
        total = total + (previous_year // 400)
        return total

    def day_of_year(year, month, day):
        month_lengths = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
        if is_leap_year(year):
            month_lengths[1] = 29
        total = 0
        index = 0
        while index < month - 1:
            total = total + month_lengths[index]
            index = index + 1
        total = total + day
        return total

    def absolute_day_number(year, month, day):
        total = days_before_year(year)
        total = total + day_of_year(year, month, day)
        return total

